from collections import Counter

class Solution(object):
    def longestBalanced(self, s):
        n = len(s)
        best = 0
        for i in range(n):
            freq = Counter()
            for j in range(i, n):
                freq[s[j]] += 1
                counts = set(freq.values())
                if len(counts) == 1:  # all distinct chars have same count
                    best = max(best, j - i + 1)
        return best
